{
  "model_id": "AGT-2024-001",
  "document_version": "1.2",
  "sections": {
    "purpose_and_scope": {
      "business_problem": "Route support tickets and draft initial responses to reduce handling time by 40%.",
      "intended_users": "Support queue management system (automated); human agents review drafts before sending.",
      "out_of_scope": ["Final send decisions", "Escalation authorisation", "Refund processing"]
    },
    "methodology": {
      "model_type": "LLM-based agent",
      "llm_provider": "Anthropic",
      "llm_version": "claude-3-5-sonnet-20241022",
      "architecture": "Single-agent with tool use: crm_lookup, kb_search, ticket_routing_write",
      "prompt_strategy": "System prompt with persona, tool descriptions, and output format constraints",
      "prompt_version": "v14 — committed to git; sha=abc123"
    },
    "data_and_inputs": {
      "input_fields": ["customer_message", "crm_record", "kb_search_results"],
      "data_classifications": ["PII", "Internal"],
      "data_freshness": "Real-time CRM lookup at inference time"
    },
    "limitations_and_known_risks": [
      "May misclassify highly ambiguous tickets; compensated by human review of draft before send.",
      "Performance degrades on languages other than English and Spanish.",
      "Does not handle tickets referencing unreleased products; routes to 'unknown' queue."
    ],
    "monitoring_plan": {
      "kris": [
        {"name": "ticket_misroute_rate", "threshold": 0.02, "frequency": "daily"},
        {"name": "draft_rejection_rate", "threshold": 0.15, "frequency": "weekly"},
        {"name": "tool_error_rate", "threshold": 0.005, "frequency": "daily"}
      ],
      "escalation_trigger": "Any KRI breaching threshold for 3 consecutive days triggers Risk Steward review."
    }
  }
}
